const AWS = require('aws-sdk');
const s3 = new AWS.S3({ region: 'your-region' });

exports.handler = async (event) => {
    const bucket = event.Records[0].s3.bucket.name;
    const key = event.Records[0].s3.object.key;

    try {
        // Read the file from S3
        const params = { Bucket: bucket, Key: key };
        const data = await s3.getObject(params).promise();

        // Process the file (insert your processing logic here)
        const processedData = await processFile(data.Body.toString());

        // Save results to another S3 location
        const outputBucket = 'your-output-bucket';
        const outputKey = `${key.split('.')[0]}_output.${key.split('.').pop()}`;
        const paramsOutput = { Bucket: outputBucket, Key: outputKey, Body: processedData };

        await s3.putObject(paramsOutput).promise();

        console.log('File successfully processed and saved to S3');
    } catch (err) {
        console.error(err);
    }
};

